// Boletas de nómina — v0.2 (sin duplicado)

function formatBoleta(nombre, tipo, bruto, neto) {
  let boleta = '';
  boleta = boleta + 'Empleado: ' + nombre + '\\n';
  boleta = boleta + 'Tipo: ' + tipo + '\\n';
  boleta = boleta + 'Bruto: $' + bruto.toFixed(2) + '\\n';
  boleta = boleta + 'Neto: $' + neto.toFixed(2) + '\\n';
  return boleta;
}

function generarBoletaEmpleado(emp) {
  const bruto = emp.salarioBase;
  const neto = bruto - bruto * 0.04 - bruto * 0.04;
  return formatBoleta(emp.nombre, 'EMPLEADO', bruto, neto);
}

function generarBoletaContratista(c) {
  const bruto = c.honorarios;
  const neto = bruto - bruto * 0.10;
  return formatBoleta(c.nombre, 'CONTRATISTA', bruto, neto);
}

