const r = generarBoletaEmpleado({ nombre: 'Ana', salarioBase: 3000 });
if (!r.includes('Ana') || !r.includes('EMPLEADO'))
  throw new Error('La boleta debe incluir nombre y tipo EMPLEADO');
if (!r.includes('Neto: $'))
  throw new Error('La boleta debe incluir el neto');

const r = generarBoletaContratista({ nombre: 'Beto', honorarios: 5000 });
if (!r.includes('Beto') || !r.includes('CONTRATISTA'))
  throw new Error('La boleta debe incluir nombre y tipo CONTRATISTA');

const r = generarBoletaEmpleado({ nombre: 'Carla', salarioBase: 2000 });
const bruto = 2000;
const esperado = bruto - bruto * 0.04 - bruto * 0.04;
if (!r.includes(esperado.toFixed(2)))
  throw new Error(`La boleta debe mostrar el neto ${esperado.toFixed(2)}`);
